```python
class SimpleStack:
    def __init__(self):
        self.items = []

    # 스택에 요소 추가 (push)
    def push(self, item):
        self.items.append(item)

    # 스택에서 최상위 요소 제거(pop) 
    def pop(self):  
        if not self.is_empty():
            return self.items.pop()

    # 스택의 최상위 요소 반환(peek), 비어있지 않다면
    def peek(self):
      return self.items[-1] if not self.is_empty() else None

    # 비어있는가?
    def is_empty(self):  
        return len(self.items) == 0  

def validate_brackets(bracket_string: str) -> bool:

    bracket_map = {')': '(', ']': '[', '}': '{'}
    openers, closers = set('([{')), set(')]}')
    stack = SimpleStack()

    for char in bracket_string:

        if char in openers:
            # 만약 문자가 오픷어라면 스택에 추가
            stack.push(char)

        elif char in closers:  
            # 캐러스트만들기
            if not stack.is_empty() and stack.peek() == bracket_map[char]:
                stack.pop()

    return len(stack.items) == 0


# 사용 예시:
